import type React from 'react';

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '../utils/cn';

const statusIndicatorVariants = cva('shrink-0', {
  variants: {
    variant: {
      dot: 'rounded-full',
      bar: 'rounded-sm w-full',
    },
    size: {
      sm: '',
      md: '',
      lg: '',
    },
    state: {
      runtime: 'bg-load-state-runtime',
      idle: 'bg-load-state-idle',
      offline: 'bg-load-state-offline',
      planned: 'bg-load-state-planned',
      nodata: 'bg-load-state-nodata',
    },
  },
  compoundVariants: [
    // Dot sizes
    { variant: 'dot', size: 'sm', class: 'h-2 w-2' },
    { variant: 'dot', size: 'md', class: 'h-3 w-3' },
    { variant: 'dot', size: 'lg', class: 'h-4 w-4' },
    // Bar sizes
    { variant: 'bar', size: 'sm', class: 'h-1' },
    { variant: 'bar', size: 'md', class: 'h-2' },
    { variant: 'bar', size: 'lg', class: 'h-3' },
  ],
  defaultVariants: {
    variant: 'dot',
    size: 'md',
    state: 'nodata',
  },
});

type StatusIndicatorProps = React.ComponentProps<'span'> &
  VariantProps<typeof statusIndicatorVariants>;

/**
 * A pure CSS colored dot or bar showing device load state.
 *
 * Use `variant="dot"` for inline status indicators next to text,
 * or `variant="bar"` for horizontal bars in charts and timelines.
 */
function StatusIndicator({
  className,
  variant,
  size,
  state,
  ...props
}: StatusIndicatorProps) {
  return (
    <span
      data-slot="status-indicator"
      className={cn(statusIndicatorVariants({ variant, size, state }), className)}
      {...props}
    />
  );
}

export { StatusIndicator, statusIndicatorVariants };
export type { StatusIndicatorProps };
